/* Define a function */
f(x) := x^2 + 2*x + 1;
f(5)

/* Piecewise function */
g(x) := if x >= 0 then sqrt(x) else -sqrt(-x);
[g(4), g(-9)]

/* Block with local variables */
block([s: 0],
  for i: 1 thru 100 do s: s + i,
  s)

/* Recursive function: Fibonacci */
fib(n) := if n <= 1 then n else fib(n-1) + fib(n-2);
makelist(fib(i), i, 0, 12)
